const response = $input.first().json;
const text = response.content?.[0]?.text || '{"posts":[]}';
let calendar;
try {
  calendar = JSON.parse(text);
} catch(e) {
  const match = text.match(/\{[\s\S]*\}/);
  calendar = match ? JSON.parse(match[0]) : { posts: [] };
}

const client = $('Por cada cliente').first().json;
return calendar.posts.map(post => ({
  json: { ...post, client_id: client.id, client_name: client.business_name, brand_guidelines: client.brand_guidelines }
}));

const response = $input.first().json;
const text = response.content?.[0]?.text || '{}';
let copy;
try {
  copy = JSON.parse(text);
} catch(e) {
  const match = text.match(/\{[\s\S]*\}/);
  copy = match ? JSON.parse(match[0]) : { body: 'Error generando copy', hashtags: '', cta: '', image_prompt: '' };
}

const post = $('Parsear Calendario').first().json;
const weekNum = Math.ceil((new Date().getDate()) / 7);

return [{
  json: {
    client_id: post.client_id,
    platform: post.platform,
    content_type: post.content_type,
    title: post.title,
    body: copy.body,
    hashtags: copy.hashtags,
    cta: copy.cta,
    image_prompt: copy.image_prompt,
    status: 'pending_review',
    batch_id: `${post.client_id}_w${weekNum}`,
    subagents_used: ['pulse.strategy', 'copy.social']
  }
}];
